@Component
class OidcAuthenticationFilter extends OncePerRequestFilter {

    private final OidcClientService oidcClientService;

    OidcAuthenticationFilter(OidcClientService oidcClientService) {
        this.oidcClientService = oidcClientService;
    }

    @Override
    protected void doFilterInternal(HttpServletRequest request, HttpServletResponse response, FilterChain filterChain) throws ServletException, IOException {
        String code = request.getParameter("code");
        String state = request.getParameter("state");
        String sessionState = (String) request.getSession().getAttribute("OIDC_STATE");

        if (code != null && state != null && state.equals(sessionState) && SecurityContextHolder.getContext().getAuthentication() == null) {
            OidcUserSession session = oidcClientService.authenticate(code);
            Authentication authentication = new UsernamePasswordAuthenticationToken(
                    session,
                    "N/A",
                    session.getAuthorities()
            );
            SecurityContextHolder.getContext().setAuthentication(authentication);
            request.getSession().setAttribute("OIDC_USER_SESSION", session);
            response.sendRedirect("/home");
            return;
        }

        filterChain.doFilter(request, response);
    }
}

class OidcClientService {

    private final RestTemplate restTemplate;
    private final JwtDecoder jwtDecoder;
    private final String clientId;
    private final String clientSecret;
    private final String authorizationEndpoint;
    private final String tokenEndpoint;
    private final String userInfoEndpoint;
    private final String redirectUri;

    OidcClientService(RestTemplate restTemplate,
                      JwtDecoder jwtDecoder,
                      String clientId,
                      String clientSecret,
                      String authorizationEndpoint,
                      String tokenEndpoint,
                      String userInfoEndpoint,
                      String redirectUri) {
        this.restTemplate = restTemplate;
        this.jwtDecoder = jwtDecoder;
        this.clientId = clientId;
        this.clientSecret = clientSecret;
        this.authorizationEndpoint = authorizationEndpoint;
        this.tokenEndpoint = tokenEndpoint;
        this.userInfoEndpoint = userInfoEndpoint;
        this.redirectUri = redirectUri;
    }

    public String buildAuthorizationUrl(HttpServletRequest request) {
        String state = UUID.randomUUID().toString();
        String nonce = UUID.randomUUID().toString();
        request.getSession().setAttribute("OIDC_STATE", state);
        request.getSession().setAttribute("OIDC_NONCE", nonce);

        return UriComponentsBuilder.fromHttpUrl(authorizationEndpoint)
                .queryParam("response_type", "code")
                .queryParam("client_id", clientId)
                .queryParam("redirect_uri", redirectUri)
                .queryParam("scope", "openid profile email")
                .queryParam("state", state)
                .queryParam("nonce", nonce)
                .build(true)
                .toUriString();
    }

    public OidcUserSession authenticate(String code) {
        TokenResponse tokenResponse = exchangeCodeForTokens(code);
        Jwt idToken = jwtDecoder.decode(tokenResponse.getIdToken());
        Map<String, Object> claims = idToken.getClaims();

        String subject = asString(claims.get(IdTokenClaimNames.SUB));
        String name = firstNonBlank(asString(claims.get("name")), asString(claims.get("preferred_username")), subject);
        String email = asString(claims.get("email"));
        String nonce = asString(claims.get("nonce"));

        Map<String, Object> userInfo = fetchUserInfo(tokenResponse.getAccessToken());
        if (userInfo != null) {
            if (name == null) name = firstNonBlank(asString(userInfo.get("name")), asString(userInfo.get("preferred_username")), subject);
            if (email == null) email = asString(userInfo.get("email"));
        }

        List<SimpleGrantedAuthority> authorities = new ArrayList<>();
        authorities.add(new SimpleGrantedAuthority("ROLE_USER"));

        return new OidcUserSession(
                subject,
                name,
                email,
                nonce,
                tokenResponse.getAccessToken(),
                tokenResponse.getRefreshToken(),
                tokenResponse.getIdToken(),
                authorities,
                claims,
                userInfo
        );
    }

    private TokenResponse exchangeCodeForTokens(String code) {
        HttpHeaders headers = new HttpHeaders();
        headers.setContentType(MediaType.APPLICATION_FORM_URLENCODED);
        headers.setBasicAuth(clientId, clientSecret, StandardCharsets.UTF_8);

        MultiValueMap<String, String> form = new LinkedMultiValueMap<>();
        form.add("grant_type", "authorization_code");
        form.add("code", code);
        form.add("redirect_uri", redirectUri);
        form.add("client_id", clientId);

        HttpEntity<MultiValueMap<String, String>> entity = new HttpEntity<>(form, headers);
        ResponseEntity<Map> response = restTemplate.postForEntity(tokenEndpoint, entity, Map.class);
        Map<String, Object> body = response.getBody();
        if (body == null) {
            throw new IllegalStateException("Empty token response");
        }

        return new TokenResponse(
                asString(body.get("access_token")),
                asString(body.get("refresh_token")),
                asString(body.get("id_token")),
                asString(body.get("token_type")),
                toLong(body.get("expires_in"))
        );
    }

    private Map<String, Object> fetchUserInfo(String accessToken) {
        if (userInfoEndpoint == null || userInfoEndpoint.isBlank()) {
            return Collections.emptyMap();
        }
        HttpHeaders headers = new HttpHeaders();
        headers.setBearerAuth(accessToken);
        HttpEntity<Void> entity = new HttpEntity<>(headers);
        ResponseEntity<Map> response = restTemplate.exchange(userInfoEndpoint, HttpMethod.GET, entity, Map.class);
        Map<String, Object> body = response.getBody();
        return body == null ? Collections.emptyMap() : body;
    }

    private static String asString(Object value) {
        return value == null ? null : String.valueOf(value);
    }

    private static Long toLong(Object value) {
        if (value == null) return null;
        if (value instanceof Number n) return n.longValue();
        try {
            return Long.parseLong(String.valueOf(value));
        } catch (Exception e) {
            return null;
        }
    }

    private static String firstNonBlank(String... values) {
        for (String v : values) {
            if (v != null && !v.isBlank()) return v;
        }
        return null;
    }
}

