@RestController
class WebController {

    @Value("${oidc.provider.authorization-endpoint}")
    private String authorizationEndpoint;

    private final OidcClientService oidcClientService;

    WebController(OidcClientService oidcClientService) {
        this.oidcClientService = oidcClientService;
    }

    @GetMapping("/")
    public String index(HttpServletRequest request) {
        Authentication auth = SecurityContextHolder.getContext().getAuthentication();
        if (auth != null && auth.isAuthenticated() && auth.getPrincipal() instanceof OidcUserSession session) {
            return "Hello " + session.getName() + " (" + session.getEmail() + ")";
        }
        return "<a href=\"/login\">Login with OIDC</a>";
    }

    @GetMapping("/login")
    public void login(HttpServletRequest request, HttpServletResponse response) throws IOException {
        String url = oidcClientService.buildAuthorizationUrl(request);
        response.sendRedirect(url);
    }

    @GetMapping("/home")
    public String home() {
        Authentication auth = SecurityContextHolder.getContext().getAuthentication();
        if (auth != null && auth.getPrincipal() instanceof OidcUserSession session) {
            return "Authenticated user: " + session.getName() + ", subject: " + session.getSubject();
        }
        return "Not authenticated";
    }

    @GetMapping("/logout")
    public void logout(HttpServletRequest request, HttpServletResponse response) throws IOException {
        new SecurityContextLogoutHandler().logout(request, response, SecurityContextHolder.getContext().getAuthentication());
        request.getSession().invalidate();
        response.sendRedirect("/");
    }
}